=Clasifica este correo y responde solo json.

ASUNTO: {{$json.subject || ''}}

REMITENTE: {{$json.from?.emailAddress?.address || ''}}

CUERPO: {{$json.bodyPreview || ''}}

=Draft the reply in the same language as the customer's email and respond only with json.


CLASIFICACION CANONICA: {{$json.clasificacion_canonica}}

INSTRUCCION OPERATIVA: 
 ASUNTO: {{$json.asunto}}

REMITENTE: {{$json.remitente}}

CUERPO: {{$json.cuerpo_original}}

parameters.jsCode:
function parseAiPayload(input) {
  const candidates = [
    input?.message?.content,
    input?.text,
    input?.response,
    input?.output,
    input,
  ];

  for (const candidate of candidates) {
    let parsed = null;
    if (typeof candidate === 'string') {
      const cleaned = candidate.replace(/```json/gi, '').replace(/```/g, '').trim();
      try {
        parsed = JSON.parse(cleaned);
      } catch (error) {
        parsed = null;
      }
    } else if (candidate && typeof candidate === 'object') {
      parsed = candidate;
    }

    if (parsed && typeof parsed === 'object') {
      return parsed;
    }
  }

  return {};
}

// 1. Extraemos solo la respuesta de la IA
const draftPayload = parseAiPayload($json || {});
const respuesta = (draftPayload.respuesta_ia || draftPayload.borrador || draftPayload.reply || '').toString().trim();

// 2. Extraemos los metadatos puros directo del trigger de Outlook para que nunca falle
const outlook = $('Outlook Trigger').item.json || {};
const clasificacionReal = $('Filtro Correo entrante').item.json['clasificacion.email'] || 'Clasificacion pendiente';

return {
  json: {
    asunto: outlook.subject || '',
    remitente: (outlook.from?.emailAddress?.address || ''),
    cuerpo_original: outlook.bodyPreview || '',
    clasificacion: clasificacionReal,
    respuesta_ia: respuesta,
  },
};

